-- ============================================================
-- 104b — Seed: Index Definitions and Index Members
-- Depends on: 103f (sport_index assets must exist), 104
-- Idempotent: INSERT ... ON CONFLICT DO NOTHING
--
-- Populates:
--   index_definitions  4 rows  (one per sport_index asset)
--   index_members     96 rows  (32 PFPI + 8 PBSI + 4 MMACI + 52 FF100)
--
-- Asset UUID conventions already established in 103a–103f:
--   Team stocks:    60000000-0000-{team:04d}-0004-000000000001
--   Player coins:   60000000-0000-{team:04d}-0005-000000000001 (QB1 = role 001)
--   Futures:        60000000-0000-0000-0002-00000000000{N}
--   Meme coins:     60000000-0000-0000-0003-00000000000{N}
--   Sport indexes:  60000000-0000-0000-0001-00000000000{N}
--
-- Index def UUIDs use prefix 80000000-0000-0000-0001-00000000000{N}
-- Index member UUIDs use prefix 90000000-{index_num:04d}-{seq:04d}-0000-000000000001
--
-- Weight notes:
--   PFPI  — 32 team stocks × 3.0 % =  96 %  (equal-weighted, ≈ 100)
--   PBSI  —  8 QB1 star coins × 12.5 % = 100 %
--             Note: no basketball-specific assets exist in v1 seed;
--             PBSI is bootstrapped with the 8 featured-team QB1 player
--             coins as "top-tier star player" proxies. Replace/extend
--             when basketball assets are added.
--   MMACI —  4 MMA/chaos assets summing to 100 %
--   FF100 — 32 team stocks (2.0 %) + 8 QB1 coins (2.0 %)
--           + 6 meme coins (2.0 %) + 6 futures (1.0 %) = 98 %  (≈ 100)
-- ============================================================

-- ─────────────────────────────────────────────────────────────
-- INDEX DEFINITIONS
-- ─────────────────────────────────────────────────────────────
   '60000000-0000-0000-0001-000000000001',
   'Pro Football Power Index',
   'Equal-weighted basket of all 32 simulated pro football team stocks. '
   'Broad market barometer for the pro football sector. Lower volatility '
   'than individual team stocks — diversification at work.',
   'equal'),

  ('80000000-0000-0000-0001-000000000002',
   '60000000-0000-0000-0001-000000000002',
   'Pro Basketball Stars Index',
   'Top-tier featured-team QB1 player coins used as star-player proxies '
   'in the v1 seed (no basketball-specific assets exist yet). Tracks '
   'high-narrative, skill-position performance across featured franchises.',
   'equal'),

  ('80000000-0000-0000-0001-000000000003',
   '60000000-0000-0000-0001-000000000003',
   'MMA Chaos Index',
   'High-volatility basket combining the MMA championship future with '
   'chaos-and-upset meme coins. Concentrated exposure to unpredictable, '
   'event-driven market swings.',
   'market_cap'),

  ('80000000-0000-0000-0001-000000000004',
   '60000000-0000-0000-0001-000000000004',
   'Fanfolio 100',
   'The flagship all-sports index. Tracks 32 team stocks, 8 featured QB1 '
   'player coins, all 6 meme coins, and all 6 futures markets — the '
   'broadest available market barometer across the Fanfolio universe.',
   'equal')
on conflict (asset_id) do nothing;

-- ─────────────────────────────────────────────────────────────
-- PFPI MEMBERS — 32 pro football team stocks (3.0 % each ≈ 96 %)
-- ─────────────────────────────────────────────────────────────
on conflict (index_id, asset_id) do nothing;

-- ─────────────────────────────────────────────────────────────
-- PBSI MEMBERS — 8 featured-team QB1 player coins (12.5 % each = 100 %)
-- ─────────────────────────────────────────────────────────────
on conflict (index_id, asset_id) do nothing;

-- ─────────────────────────────────────────────────────────────
-- MMACI MEMBERS — MMA championship future + chaos meme coins (100 %)
-- ─────────────────────────────────────────────────────────────
on conflict (index_id, asset_id) do nothing;

-- ─────────────────────────────────────────────────────────────
-- FF100 MEMBERS — flagship all-sports index (≈ 98 %)
--   Seq 0001–0032 : 32 team stocks        @ 2.0 % each = 64 %
--   Seq 0033–0040 : 8 featured QB1 coins  @ 2.0 % each = 16 %
--   Seq 0041–0046 : 6 meme coins          @ 2.0 % each = 12 %
--   Seq 0047–0052 : 6 futures             @ 1.0 % each =  6 %
--                                                  Total ≈ 98 %
-- ─────────────────────────────────────────────────────────────

-- Team stocks (32)
on conflict (index_id, asset_id) do nothing;

-- Featured QB1 player coins (8)
on conflict (index_id, asset_id) do nothing;

-- Meme coins (6)
on conflict (index_id, asset_id) do nothing;

-- Futures (6)
on conflict (index_id, asset_id) do nothing;
